import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { transporter } from "@/lib/email";

export async function POST(req: Request) {
  try {
    const { email, status } = await req.json();

    if (!email || status === undefined) {
      return NextResponse.json(
        { error: "Email and status are required" },
        { status: 400 }
      );
    }

    // Fetch user details
    const [users] = (await db.query(
      "SELECT id, name, email FROM users WHERE email = ?",
      [email]
    )) as any[];

    if (!users.length) {
      return NextResponse.json({ error: "User not found" }, { status: 404 });
    }

    const user = users[0];

    const [reminders] = (await db.query(
      "SELECT appointment_date FROM reminder WHERE user_id = ?",
      [user.id]
    )) as any[];

    if (!reminders.length) {
      return NextResponse.json(
        { error: "No appointment found for this user" },
        { status: 404 }
      );
    }

    const appointmentDate = new Date(
      reminders[0].appointment_date
    ).toDateString();

    // If status is 1, do not send the email
    if (status === 0) {
      return NextResponse.json({
        message: "Email not sent as you are rejected by the embassy.",
      });
    }

    // If status is 0, send a reminder email
    await transporter.sendMail({
      from: `"BringUrBuddy" <${process.env.EMAIL_USER}>`,
      to: user.email,
      subject: "Appointment Reminder - BringUrBuddy",
      html: `
        <p>Dear <strong>${user.name}</strong>,</p>
        <p>This is a reminder for your upcoming appointment after the embassy.</p>
        <p><strong>Appointment Date:</strong> ${appointmentDate}</p>
        <p>Please ensure you are prepared and on time.</p>
        <p>Best Regards,<br><strong>BringUrBuddy Team</strong></p>
      `,
    });

    return NextResponse.json({ message: "Reminder email sent successfully." });
  } catch (error) {
    console.error("Error sending reminder email:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 }
    );
  }
}
